import { useState, useEffect, useRef, useMemo } from 'react'
import { generatePGN, getPGNResult, formatPGNTimeControl } from '@/shared/chess/engine/pgn.js'
import { useChessTimer } from './hooks/useChessTimer'
import { useGameEngine, isPromotionTag, getPromotionPieceType } from './hooks/useGameEngine'
import { usePawnPromotion } from './hooks/usePawnPromotion'
import { useReviewMode } from './hooks/useReviewMode'
import { playMoveSound, playCaptureSound, playCheckSound, playCastleSound, playGameStartSound, playGameEndSound, playPromotionSound, setSoundPreferences } from './utils/sounds'
import Sidebar from './components/Sidebar'
import RightPanel from './components/RightPanel'
import GamePanel from './components/GamePanel'
import PawnPromotionUI from './components/PawnPromotionUI'
import GameOverModal from './components/GameOverModal'
import DrawOfferModal from './components/DrawOfferModal'
import { BACKGROUND_PRESETS, DEFAULT_UI_SETTINGS, BOARD_THEME_MAP, BOARD_TEXTURE_MAP } from './constants/boardThemes'
import { THEME_PRESET_MAP } from './constants/uiPresets.js'
import SettingsModal from './components/SettingsModal'
import GameSettingsModal from './components/GameSettingsModal'
import ModeSelectScreen from './components/ModeSelectScreen'
import MultiplayerLobbyScreen from './components/MultiplayerLobbyScreen'
import { initBitboardEngine } from '@/shared/chess/engine/index.js'
import { useStockfish } from './hooks/useStockfish'
import { useP2PGame } from './hooks/useP2PGame'
import BoardContainer from './features/board/BoardContainer';
import MobileNavigation from './features/navigation/MobileNavigation';
import MobileGameArea from './features/game/MobileGameArea';
import GameModals from './features/game/GameModals';
import { useAssetManifest } from './features/assets/useAssetManifest';
import { useAtomValue } from 'jotai';
import { uiSettingsAtom } from './state/themeState';
import { sanitizeUiSettings, readStoredJson } from './features/settings/storage';
import { useReviewController } from './features/review/useReviewController';
import { useMultiplayerController } from './features/multiplayer/useMultiplayerController';
import { useGameLifecycle } from './features/game/useGameLifecycle';
import { useMoveExecution } from './features/game/useMoveExecution';
import { useComputerMove } from './features/game/useComputerMove';
import { openGameAnalysis } from './features/review/analysisHandoff';
import {
  getDifficultySettings,
  ENGINE_PROFILES,
  DEFAULT_ENGINE_PROFILE,
  DEFAULT_LIVE_EVAL_SETTINGS,
  DEFAULT_ANALYSIS_SETTINGS,
  clampLiveEvalSettings,
  clampAnalysisSettings,
} from './utils/stockfishUtils'
import { buildPieceImages } from './constants/theme'

const UI_STATES = {
  MODE_SELECT: 'mode_select',
  MULTIPLAYER_LOBBY: 'multiplayer_lobby',
  LOCAL_GAME: 'local_game',
  GAME_OVER: 'game_over',
  REVIEW: 'review'
};

const UI_STATE_CAPABILITIES = {
  [UI_STATES.MODE_SELECT]: {
    canMovePieces: false,
    canUseInGameActions: false,
    canStartGame: false,
    canOpenMultiplayer: false,
  },
  [UI_STATES.MULTIPLAYER_LOBBY]: {
    canMovePieces: false,
    canUseInGameActions: false,
    canStartGame: false,
    canOpenMultiplayer: false,
  },
  [UI_STATES.LOCAL_GAME]: {
    canMovePieces: true,
    canUseInGameActions: true,
    canStartGame: true,
    canOpenMultiplayer: true,
  },
  [UI_STATES.GAME_OVER]: {
    canMovePieces: false,
    canUseInGameActions: false,
    canStartGame: false,
    canOpenMultiplayer: false,
  },
  [UI_STATES.REVIEW]: {
    canMovePieces: false,
    canUseInGameActions: false,
    canStartGame: false,
    canOpenMultiplayer: false,
  },
};

const STORAGE_KEYS = {
  ENGINE_PROFILE: 'stockfish_engine_profile_v1',
  LIVE_EVAL: 'stockfish_live_eval_settings_v1',
  ANALYSIS: 'stockfish_analysis_settings_v1',
  UI_SETTINGS: 'chess_ui_settings_v1',
};

function App() {
  const ANALYSIS_HANDOFF_KEY = 'chessapp_analysis_handoff_v1';

  // ── Engine init ──────────────────────────────────────────────────
  useEffect(() => {
    initBitboardEngine();
  }, []);

  // ── Game Engine ──────────────────────────────────────────────────
  const {
    displayPieces,
    legalMovesMap,
    fen,
    checkInfo,
    gameStatus,
    sideToMove,
    moveHistory,
    capturedPieces,
    lastMoveInfo,
    executeMove: engineExecuteMove,
    resetGame: engineResetGame,
    getReviewSnapshots,
  } = useGameEngine();

  const board = displayPieces;
  const currentTurn = sideToMove;
  const kingInCheckPos = checkInfo.kingSquare;
  const lastMove = lastMoveInfo;

  // ── Manual game end (resignation, draw, timeout) ────────────────
  const [manualGameEnd, setManualGameEnd] = useState(null);
  const gameState = manualGameEnd || gameStatus;

  // ── Square selection ─────────────────────────────────────────────
  const [selectedSquare, setSelectedSquare] = useState(null);
  const [validMoves, setValidMoves] = useState([]);

  const clearSelection = () => {
    setSelectedSquare(null);
    setValidMoves([]);
  };

  // ── Pawn promotion ───────────────────────────────────────────────
  const {
    showPromotionUI,
    promotionSquare,
    pendingPromotionMoves,
    initiatePromotion,
    completePromotion,
    cancelPromotion
  } = usePawnPromotion();

  // ── Review mode ──────────────────────────────────────────────────
  const {
    isReviewMode,
    reviewIndex,
    reviewHistoryLength,
    isPlaying,
    enterReviewMode,
    exitReviewMode,
    goToPrevious,
    goToNext,
    goToStart,
    goToEnd,
    toggleAutoPlay,
    getCurrentReviewState,
  } = useReviewMode();

  // ── Timer state ──────────────────────────────────────────────────
  const [whiteTime, setWhiteTime] = useState(600000);
  const [blackTime, setBlackTime] = useState(600000);
  const [isTimerActive, setIsTimerActive] = useState(false);

  const [selectedTimeControl, setSelectedTimeControl] = useState({
    base: 600,
    increment: 0,
    label: '10 min',
    category: 'rapid',
    icon: '🕐'
  });

  // ── Game flow state ──────────────────────────────────────────────
  const [gameStarted, setGameStarted] = useState(false);
  const [showGameOverUI, setShowGameOverUI] = useState(false);
  const [currentPGN, setCurrentPGN] = useState('');
  const [showDrawOffer, setShowDrawOffer] = useState(false);
  const [incomingDrawOfferSide, setIncomingDrawOfferSide] = useState(null);
  const [multiplayerNotice, setMultiplayerNotice] = useState('');
  const [isBoardFlipped, setIsBoardFlipped] = useState(false);
  const [showAppSettings, setShowAppSettings] = useState(false);
  const [showGameSettings, setShowGameSettings] = useState(false);

  const [playerNames, setPlayerNames] = useState({
    white: 'White',
    black: 'Black'
  });

  // ── Mode / multiplayer state ─────────────────────────────────────
  const [entryMode, setEntryMode] = useState(null);
  const [isMultiplayerGame, setIsMultiplayerGame] = useState(false);
  const [multiplayerSide, setMultiplayerSide] = useState('w');
  const [isMultiplayerStarted, setIsMultiplayerStarted] = useState(false);

  const remoteApplyingMoveRef = useRef(false);

  // ── Computer / game mode state ───────────────────────────────────
  const [gameMode, setGameMode] = useState('human');
  const [playerColor, setPlayerColor] = useState('white');
  const [computerDifficulty, setComputerDifficulty] = useState(5);

  // ── Engine / Stockfish config (read-only, loaded once) ───────────
  const [engineProfile] = useState(() => {
    const stored = readStoredJson(
      STORAGE_KEYS.ENGINE_PROFILE,
      DEFAULT_ENGINE_PROFILE
    );
    return ENGINE_PROFILES.some(p => p.id === stored)
      ? stored
      : DEFAULT_ENGINE_PROFILE;
  });

  const [liveEvalConfig] = useState(() => {
    const stored = readStoredJson(
      STORAGE_KEYS.LIVE_EVAL,
      DEFAULT_LIVE_EVAL_SETTINGS
    );
    return clampLiveEvalSettings(stored);
  });

  const [analysisConfig] = useState(() => {
    const stored = readStoredJson(
      STORAGE_KEYS.ANALYSIS,
      DEFAULT_ANALYSIS_SETTINGS
    );
    return clampAnalysisSettings(stored);
  });

  // ── UI settings (via Jotai) ──────────────────────────────────────
  const uiSettings = useAtomValue(uiSettingsAtom);

  // ── Asset manifest ───────────────────────────────────────────────
  const {
    assetManifest,
    dynamicBoardImageMap,
    boardSurfaceOptions,
    pieceSetOptions
  } = useAssetManifest();

  // ── Board theme colors ────────────────────────────────────────────
  const boardThemeColors = useMemo(() => {
    const preset =
      BOARD_THEME_MAP[uiSettings.boardTheme] ||
      BOARD_THEME_MAP['classic-blue'];

    return {
      ...preset,
      light: uiSettings.useCustomBoardColors
        ? (uiSettings.customLightSquare || preset.light)
        : preset.light,
      dark: uiSettings.useCustomBoardColors
        ? (uiSettings.customDarkSquare || preset.dark)
        : preset.dark,
      textureImage: BOARD_TEXTURE_MAP[uiSettings.boardTexture] || null,
      boardImage: dynamicBoardImageMap[uiSettings.boardSurface] || null,
    };
  }, [
    uiSettings.boardTheme,
    uiSettings.boardSurface,
    uiSettings.customLightSquare,
    uiSettings.customDarkSquare,
    uiSettings.useCustomBoardColors,
    uiSettings.boardTexture,
    dynamicBoardImageMap,
  ]);

  const activePieceSet = uiSettings.pieceStyle || 'staunty';

  const activePieceImages = useMemo(() => {
    return buildPieceImages(
      activePieceSet,
      assetManifest.pieceFilesBySet?.[activePieceSet] || null
    );
  }, [activePieceSet, assetManifest.pieceFilesBySet]);

  const appBackgroundStyle = useMemo(() => {
    if (uiSettings.backgroundStyle === 'bg-custom-solid') {
      return {
        background:
          uiSettings.customBackgroundColor || '#17212c',
      };
    }
    return (
      BACKGROUND_PRESETS[uiSettings.backgroundStyle]?.style ||
      BACKGROUND_PRESETS['bg-classic'].style
    );
  }, [
    uiSettings.backgroundStyle,
    uiSettings.customBackgroundColor
  ]);

  // ── Analysis state ───────────────────────────────────────────────
  const [reviewDisplayState, setReviewDisplayState] = useState(null);
  const [analysisStatus, setAnalysisStatus] = useState('idle');
  const [, setAnalysisResults] = useState([]);
  const [, setAnalyzedCount] = useState(0);
  const [, setWhiteAccuracy] = useState(null);
  const [, setBlackAccuracy] = useState(null);

  const analysisRunIdRef = useRef(0);
  const analysisCacheRef = useRef(new Map());
  const liveEvalRequestKeyRef = useRef('');

  // ── Board view state ─────────────────────────────────────────────
  const [boardViewKey, setBoardViewKey] = useState(0);
  const [highlightResign, setHighlightResign] = useState(false);

  const resignHighlightTimeoutRef = useRef(null);

  // ── External hooks ────────────────────────────────────────────────
  const stockfish = useStockfish({ engineProfile });
  const p2p = useP2PGame();

  // ── Persist UI settings & sync volume ────────────────────────────
  // Note: atomWithStorage handles localStorage persistence automatically.
  // This effect only bridges the volume setting to the HTML Audio player.
  useEffect(() => {
    setSoundPreferences({ volume: uiSettings.volume ?? 0.75 });
  }, [uiSettings.volume]);


  // ── Chess timer ───────────────────────────────────────────────────
  useChessTimer({
    isTimerActive,
    gameState,
    currentTurn,
    whiteTime,
    blackTime,
    setWhiteTime,
    setBlackTime,
    setGameState: setManualGameEnd,
    setIsTimerActive,
    setShowGameOverUI
  });

  // ── Stockfish evaluation values ───────────────────────────────────
  const evalValue =
    stockfish.evaluation?.type === 'cp'
      ? stockfish.evaluation.value
      : null;

  const mateValue =
    stockfish.evaluation?.type === 'mate'
      ? stockfish.evaluation.value
      : null;

  // ── Active board state (live or review) ───────────────────────────
  const activeBoard =
    isReviewMode && reviewDisplayState
      ? reviewDisplayState.displayPieces
      : board;

  const activeKingInCheckPos =
    isReviewMode && reviewDisplayState
      ? reviewDisplayState.kingInCheckPos
      : kingInCheckPos;

  const activeLastMove =
    isReviewMode && reviewDisplayState
      ? reviewDisplayState.lastMoveInfo
      : lastMove;

  const activeCapturedPieces =
    isReviewMode && reviewDisplayState
      ? reviewDisplayState.capturedPieces
      : capturedPieces;

  const activeMoveHistory =
    isReviewMode && reviewDisplayState
      ? (reviewDisplayState.moveHistory || moveHistory)
      : moveHistory;

  // BUG-15 FIX: Check isReviewMode BEFORE showGameOverUI so that the review
  // screen is never covered by the game-over overlay.
  const uiState = useMemo(() => {
    if (!entryMode) return UI_STATES.MODE_SELECT;
    if (entryMode === 'multiplayer')
      return UI_STATES.MULTIPLAYER_LOBBY;
    if (isReviewMode) return UI_STATES.REVIEW;
    if (showGameOverUI && gameState !== 'playing')
      return UI_STATES.GAME_OVER;
    return UI_STATES.LOCAL_GAME;
  }, [
    entryMode,
    showGameOverUI,
    gameState,
    isReviewMode
  ]);

  const uiCapabilities = useMemo(() => {
    const base =
      UI_STATE_CAPABILITIES[uiState] ||
      UI_STATE_CAPABILITIES[UI_STATES.MODE_SELECT];

    const isLiveLocalGame =
      uiState === UI_STATES.LOCAL_GAME &&
      gameStarted &&
      gameState === 'playing';

    return {
      canMovePieces:
        base.canMovePieces &&
        isLiveLocalGame &&
        !showPromotionUI,

      canUseInGameActions:
        base.canUseInGameActions &&
        isLiveLocalGame,

      canStartGame:
        base.canStartGame &&
        !gameStarted,

      canOpenMultiplayer:
        base.canOpenMultiplayer &&
        !gameStarted,
    };
  }, [
    uiState,
    gameStarted,
    gameState,
    showPromotionUI
  ]);

  // ══════════════════════════════════════════════════════════════════
  // MOVE EXECUTION
  // Declared before handleSquareClick so performMove is available.
  // ══════════════════════════════════════════════════════════════════

  const { performMove } = useMoveExecution({
    engineExecuteMove,
    isMultiplayerGame,
    p2p,
    remoteApplyingMoveRef,
    currentTurn,
    moveHistory,
    playerNames,
    selectedTimeControl,
    setWhiteTime,
    setBlackTime,
    setShowGameOverUI,
    setIsTimerActive,
    setCurrentPGN,
    setManualGameEnd,
    clearSelection,
  });

  // ══════════════════════════════════════════════════════════════════
  // COMPUTER MOVE CONTROLLER
  // Declared before handleSquareClick (needs isComputerTurn) and
  // before useGameLifecycle (needs makeComputerMove).
  // BUG-01/12 FIX: Real makeComputerMove is created here and passed
  // to useGameLifecycle below — never use a stub.
  // ══════════════════════════════════════════════════════════════════

  const { makeComputerMove, isComputerTurn } = useComputerMove({
    stockfish,
    gameMode,
    uiCapabilities,
    fen,
    legalMovesMap,
    currentTurn,
    playerColor,
    computerDifficulty,
    performMove,
  });

  // ══════════════════════════════════════════════════════════════════
  // CLICK HANDLING
  // Both performMove and isComputerTurn are now defined above.
  // ══════════════════════════════════════════════════════════════════

  const handleSquareClick = (displayRow, displayCol) => {
    if (!uiCapabilities.canMovePieces) return;

    // Block human input when it's the computer's turn
    if (isComputerTurn()) return;

    // In multiplayer, each player can move only their own side.
    if (isMultiplayerGame && currentTurn !== multiplayerSide) return;

    const rowIndex = isBoardFlipped ? 7 - displayRow : displayRow;
    const colIndex = isBoardFlipped ? 7 - displayCol : displayCol;
    const squareIndex = rowIndex * 8 + colIndex;

    if (!selectedSquare) {
      if (legalMovesMap.has(squareIndex)) {
        const moves = legalMovesMap.get(squareIndex);
        setSelectedSquare({ row: rowIndex, col: colIndex, sq: squareIndex });

        const seen = new Set();
        const displayMoves = [];

        for (const m of moves) {
          const key = m.to;
          if (!seen.has(key)) {
            seen.add(key);
            displayMoves.push({
              row: m.to >> 3,
              col: m.to & 7
            });
          }
        }

        setValidMoves(displayMoves);
      }
    } else {
      const fromSq = selectedSquare.sq;

      if (fromSq === squareIndex) {
        clearSelection();
        return;
      }

      const fromMoves = legalMovesMap.get(fromSq) || [];
      const matchingMoves = fromMoves.filter(
        m => m.to === squareIndex
      );

      if (matchingMoves.length > 0) {
        const promoMoves = matchingMoves.filter(
          m => isPromotionTag(m.tag)
        );

        if (promoMoves.length > 0) {
          const pawnColor =
            promoMoves[0].piece <= 5 ? 'w' : 'b';

          initiatePromotion(
            promoMoves,
            displayRow,
            displayCol,
            pawnColor
          );

          clearSelection();
          return;
        }

        performMove(matchingMoves[0]);
      } else if (legalMovesMap.has(squareIndex)) {
        clearSelection();

        const moves = legalMovesMap.get(squareIndex);

        setSelectedSquare({
          row: rowIndex,
          col: colIndex,
          sq: squareIndex,
        });

        const seen = new Set();
        const displayMoves = [];

        for (const m of moves) {
          const key = m.to;

          if (!seen.has(key)) {
            seen.add(key);

            displayMoves.push({
              row: m.to >> 3,
              col: m.to & 7,
            });
          }
        }

        setValidMoves(displayMoves);
      } else {
        clearSelection();
      }
    }
  };

  // ══════════════════════════════════════════════════════════════════
  // PAWN PROMOTION
  // ══════════════════════════════════════════════════════════════════

  const handlePromotion = (pieceType) => {
    if (
      !pendingPromotionMoves ||
      pendingPromotionMoves.length === 0
    ) return;

    playPromotionSound();

    const chosen = pendingPromotionMoves.find(
      m => getPromotionPieceType(m.tag) === pieceType
    );

    if (!chosen) return;

    performMove(chosen);
    completePromotion();
  };

  const handleCancelPromotion = () => {
    cancelPromotion();
    clearSelection();
  };

  // ══════════════════════════════════════════════════════════════════
  // REVIEW MODE
  // ══════════════════════════════════════════════════════════════════

  const {
    handleGameReview,
    handleReviewPrevious,
    handleReviewNext,
    handleReviewStart,
    handleReviewEnd,
    handleReviewTogglePlay,
    handleExitReview,
  } = useReviewController({
    getReviewSnapshots,
    enterReviewMode,
    exitReviewMode,
    goToPrevious,
    goToNext,
    goToStart,
    goToEnd,
    toggleAutoPlay,
    setReviewDisplayState,
    setAnalysisStatus,
    setAnalyzedCount,
    setAnalysisResults,
    setWhiteAccuracy,
    setBlackAccuracy,
    setShowGameOverUI,
    analysisRunIdRef,
  });

  const handleOpenGameAnalysis = () => {
    const analysisTargetPly = isReviewMode
      ? Math.max(0, reviewIndex)
      : activeMoveHistory.length;

    const pgnToAnalyze =
      currentPGN && currentPGN.trim().length > 0
        ? currentPGN
        : generatePGN({
            whitePlayer:
              playerNames.white || 'White',
            blackPlayer:
              playerNames.black || 'Black',
            result: getPGNResult(
              gameState,
              currentTurn
            ),
            moveHistory,
            gameState,
            timeControl:
              formatPGNTimeControl(
                selectedTimeControl.base,
                selectedTimeControl.increment
              ),
          });

    try {
      window.localStorage.setItem(
        ANALYSIS_HANDOFF_KEY,
        JSON.stringify({
          pgn: pgnToAnalyze,
          orientation: isBoardFlipped
            ? 'black'
            : 'white',
          targetPly: analysisTargetPly,
          source: 'play-review',
          ts: Date.now(),
        })
      );
    } catch (error) {
      console.error(
        'Failed to store analysis handoff payload:',
        error
      );
    }

    const baseUrl =
      import.meta.env.BASE_URL || '/';

    const normalizedBase =
      baseUrl.endsWith('/')
        ? baseUrl
        : `${baseUrl}/`;

    const analysisUrl = new URL(
      'analysis',
      new URL(
        normalizedBase,
        window.location.href
      )
    );

    window.location.assign(
      analysisUrl.toString()
    );
  };

  // ══════════════════════════════════════════════════════════════════
  // GAME LIFECYCLE
  // ══════════════════════════════════════════════════════════════════

  const triggerResignHighlight = () => {
    setHighlightResign(true);

    if (resignHighlightTimeoutRef.current) {
      clearTimeout(resignHighlightTimeoutRef.current);
    }

    resignHighlightTimeoutRef.current = setTimeout(() => {
      setHighlightResign(false);
    }, 2200);
  };

  const {
    handleNewGame,
    handleStartConfiguredGame,
    handleRematch,
    handlePlayFriend,
    handleSelectGameMode,
    handleNewGameRequest,
    handlePlaySelectFromNav,
    handleRefreshBoardView,
  } = useGameLifecycle({
    analysisRunIdRef,
    liveEvalRequestKeyRef,
    engineResetGame,
    stockfish,
    p2p,
    isMultiplayerGame,
    remoteApplyingMoveRef,
    selectedTimeControl,
    setManualGameEnd,
    setWhiteTime,
    setBlackTime,
    setIsTimerActive,
    setGameStarted,
    setShowGameOverUI,
    setShowDrawOffer,
    setIncomingDrawOfferSide,
    setCurrentPGN,
    setReviewDisplayState,
    setAnalysisStatus,
    setAnalysisResults,
    setAnalyzedCount,
    setWhiteAccuracy,
    setBlackAccuracy,
    analysisCacheRef,
    exitReviewMode,
    clearSelection,
    setGameMode,
    setIsMultiplayerGame,
    setMultiplayerSide,
    setIsMultiplayerStarted,
    setMultiplayerNotice,
    setIsBoardFlipped,
    setEntryMode,
    p2pDisconnect: p2p.disconnect,
    playerColor,
    setPlayerColor,
    setBoardViewKey,
    setHighlightResign,
    uiCapabilities,
    triggerResignHighlight,
    playGameStartSound,
    // BUG-01/12 FIX: Pass the real makeComputerMove, not a stub.
    // This ensures handleStartConfiguredGame correctly triggers the engine
    // when gameMode === 'computer' and playerColor === 'black'.
    makeComputerMove,
    gameMode,
  });

  useEffect(() => {
    return () => {
      if (resignHighlightTimeoutRef.current) {
        clearTimeout(resignHighlightTimeoutRef.current);
      }
    };
  }, []);

  // ══════════════════════════════════════════════════════════════════
  // IN-GAME ACTION HANDLERS
  // ══════════════════════════════════════════════════════════════════

  const handleComputerDifficultyChange = (level) => {
    setComputerDifficulty(level);

    if (stockfish.isEngineReady) {
      const settings = getDifficultySettings(level);
      stockfish.setSkillLevel(settings.skill);

      console.log(`Difficulty set to level ${level}`);
    }
  };

  const handlePlayerColorChange = (color) => {
    setPlayerColor(color);
    setIsBoardFlipped(color === 'black');

    console.log(`Player color: ${color}`);
  };

  useEffect(() => {
    if (uiSettings.orientation === 'white') {
      setIsBoardFlipped(false);
    } else if (uiSettings.orientation === 'black') {
      setIsBoardFlipped(true);
    }
  }, [uiSettings.orientation]);

  const handleResign = () => {
    if (!uiCapabilities.canUseInGameActions) return;

    setHighlightResign(false);

    if (
      isMultiplayerGame &&
      p2p.isConnected &&
      !remoteApplyingMoveRef.current
    ) {
      p2p.sendMessage({
        type: 'resign',
        by: multiplayerSide,
      });
    }

    const winner =
      currentTurn === 'w'
        ? (playerNames.black || 'Black')
        : (playerNames.white || 'White');

    setManualGameEnd('resigned');
    setIsTimerActive(false);
    setShowGameOverUI(true);

    playGameEndSound();

    const pgnResult = currentTurn === 'w' ? '0-1' : '1-0';

    const pgn = generatePGN({
      whitePlayer: playerNames.white || 'White',
      blackPlayer: playerNames.black || 'Black',
      result: pgnResult,
      moveHistory,
      gameState: 'resigned',
      timeControl: formatPGNTimeControl(
        selectedTimeControl.base,
        selectedTimeControl.increment
      ),
    });

    setCurrentPGN(pgn);

    console.log('Game PGN (Resignation):', pgn);
    console.log(`${winner} wins by resignation!`);
  };

  const handleOfferDraw = () => {
    if (!uiCapabilities.canUseInGameActions) return;

    if (isMultiplayerGame) {
      if (!p2p.isConnected) {
        setMultiplayerNotice('Not connected to opponent.');
        return;
      }

      p2p.sendMessage({
        type: 'draw_offer',
        by: multiplayerSide,
      });

      setMultiplayerNotice(
        'Draw request sent. Waiting for opponent...'
      );

      return;
    }

    setShowDrawOffer(true);
  };

  const handleAcceptDraw = () => {
    if (isMultiplayerGame && incomingDrawOfferSide) {
      p2p.sendMessage({
        type: 'draw_response',
        accepted: true,
      });

      setIncomingDrawOfferSide(null);
    }

    setShowDrawOffer(false);
    setManualGameEnd('draw');
    setIsTimerActive(false);
    setShowGameOverUI(true);

    playGameEndSound();

    const pgn = generatePGN({
      whitePlayer: playerNames.white || 'White',
      blackPlayer: playerNames.black || 'Black',
      result: '1/2-1/2',
      moveHistory,
      gameState: 'draw',
      timeControl: formatPGNTimeControl(
        selectedTimeControl.base,
        selectedTimeControl.increment
      ),
    });

    setCurrentPGN(pgn);

    console.log('Game PGN (Draw by agreement):', pgn);
  };

  const handleDeclineDraw = () => {
    if (isMultiplayerGame && incomingDrawOfferSide) {
      p2p.sendMessage({
        type: 'draw_response',
        accepted: false,
      });

      setIncomingDrawOfferSide(null);
      setMultiplayerNotice('Draw request declined.');
    }

    setShowDrawOffer(false);

    console.log('Draw offer declined. Game continues.');
  };

  const handleSelectTimeControl = (control) => {
    setSelectedTimeControl(control);
    setWhiteTime(control.base * 1000);
    setBlackTime(control.base * 1000);
  };

  const updatePlayerName = (side, value) => {
    if (isMultiplayerGame) {
      if (multiplayerSide === 'w' && side !== 'white') return;
      if (multiplayerSide === 'b' && side !== 'black') return;
    }

    setPlayerNames((prev) => ({
      ...prev,
      [side]: value,
    }));

    if (isMultiplayerGame && p2p.isConnected) {
      p2p.sendMessage({
        type: 'name_update',
        side,
        value,
      });
    }
  };

  const resetPlayerNames = () => {
    if (isMultiplayerGame) return;

    setPlayerNames({
      white: 'White',
      black: 'Black',
    });
  };

  // ══════════════════════════════════════════════════════════════════
  // MULTIPLAYER CONTROLLER
  // ══════════════════════════════════════════════════════════════════

  const { startMultiplayerMatch } = useMultiplayerController({
    p2p,
    entryMode,
    isMultiplayerGame,
    gameStarted,
    selectedTimeControl,
    engineResetGame,
    setGameMode,
    setIsMultiplayerGame,
    setIsMultiplayerStarted,
    setMultiplayerSide,
    setIsBoardFlipped,
    setEntryMode,
    setMultiplayerNotice,
    setManualGameEnd,
    setShowGameOverUI,
    setShowDrawOffer,
    setIncomingDrawOfferSide,
    setGameStarted,
    setIsTimerActive,
    setWhiteTime,
    setBlackTime,
    playGameStartSound,
    remoteApplyingMoveRef,
    performMove,
    handleNewGame,
    setPlayerNames,
  });

  // ══════════════════════════════════════════════════════════════════
  // DISPLAY COMPUTATION
  // ══════════════════════════════════════════════════════════════════

  const formatTime = (timeInMs) => {
    const totalSeconds = Math.floor(timeInMs / 1000);
    const mins = Math.floor(totalSeconds / 60);
    const secs = totalSeconds % 60;
    const milliseconds = Math.floor((timeInMs % 1000) / 10);

    if (totalSeconds < 10) {
      return `${mins.toString().padStart(2, '0')}:${secs
        .toString()
        .padStart(2, '0')}:${milliseconds
        .toString()
        .padStart(2, '0')}`;
    }

    return `${mins.toString().padStart(2, '0')}:${secs
      .toString()
      .padStart(2, '0')}   `;
  };

  const fileLabels = ['a', 'b', 'c', 'd', 'e', 'f', 'g', 'h'];
  const rankLabels = ['8', '7', '6', '5', '4', '3', '2', '1'];

  const effectiveBoardFlipped =
    uiSettings.orientation === 'auto'
      ? currentTurn === 'b'
      : isBoardFlipped;

  const displayBoard = effectiveBoardFlipped
    ? [...activeBoard].reverse().map((row) => [...row].reverse())
    : activeBoard;

  const displayFileLabels = effectiveBoardFlipped
    ? [...fileLabels].reverse()
    : fileLabels;

  const displayRankLabels = effectiveBoardFlipped
    ? [...rankLabels].reverse()
    : rankLabels;

  const displaySelectedSquare =
    selectedSquare && effectiveBoardFlipped
      ? {
          row: 7 - selectedSquare.row,
          col: 7 - selectedSquare.col,
        }
      : selectedSquare;

  const displayValidMoves = effectiveBoardFlipped
    ? validMoves.map((move) => ({
        row: 7 - move.row,
        col: 7 - move.col,
      }))
    : validMoves;

  const displayKingInCheckPos =
    activeKingInCheckPos && effectiveBoardFlipped
      ? {
          row: 7 - activeKingInCheckPos.row,
          col: 7 - activeKingInCheckPos.col,
        }
      : activeKingInCheckPos;

  const displayLastMove =
    activeLastMove && effectiveBoardFlipped
      ? {
          from: {
            row: 7 - activeLastMove.from.row,
            col: 7 - activeLastMove.from.col,
          },
          to: {
            row: 7 - activeLastMove.to.row,
            col: 7 - activeLastMove.to.col,
          },
          piece: activeLastMove.piece,
        }
      : activeLastMove;

  // Derived screen-level booleans
  const isGameOverUIState = uiState === UI_STATES.GAME_OVER;
  // BUG-03 FIX: showMobileStartPanel is computed here and passed as a
  // boolean to MobileGameArea (which expects the boolean, not uiState + gameStarted).
  const showMobileStartPanel =
    uiState === UI_STATES.LOCAL_GAME && !gameStarted;
  const displayTurn = currentTurn;

  // ══════════════════════════════════════════════════════════════════
  // SCREEN ROUTING
  // ══════════════════════════════════════════════════════════════════

  // ModeSelectScreen
  if (uiState === UI_STATES.MODE_SELECT) {
    return (
      <ModeSelectScreen
        onSelectLocal={() => {
          setIsMultiplayerGame(false);
          setMultiplayerSide('w');
          setIsMultiplayerStarted(false);
          setMultiplayerNotice('');
          p2p.disconnect();
          setEntryMode('local');
        }}
        onSelectMultiplayer={() => {
          setEntryMode('multiplayer');
          setGameMode('human');
          setIsMultiplayerStarted(false);
          setMultiplayerNotice('');
        }}
      />
    );
  }

  // Multiplayer Lobby
  if (uiState === UI_STATES.MULTIPLAYER_LOBBY) {
    return (
      <MultiplayerLobbyScreen
        onBack={() => setEntryMode(null)}
        onContinueLocal={() => setEntryMode('local')}
        p2p={p2p}
        onStartMultiplayer={startMultiplayerMatch}
      />
    );
  }

  // Main Layout (LOCAL_GAME, GAME_OVER, REVIEW)
  return (
    <div
      className={`h-screen w-screen flex flex-col lg:flex-row overflow-hidden bg-cover bg-center ${
        uiSettings.reduceMotion ? 'motion-reduce' : ''
      }`}
      style={appBackgroundStyle}
    >
      <Sidebar
        onSelectGameMode={handleSelectGameMode}
        onOpenSettings={() => setShowAppSettings(true)}
        onRefresh={handleRefreshBoardView}
        onPlaySelect={handlePlaySelectFromNav}
      />

      {/* Center column: board + player cards + timers */}
      <div className="flex-1 flex flex-col items-center justify-center overflow-hidden px-2 lg:px-0">
        <BoardContainer
          key={boardViewKey}
          boardViewKey={boardViewKey}
          effectiveBoardFlipped={effectiveBoardFlipped}
          playerNames={playerNames}
          activeCapturedPieces={activeCapturedPieces}
          whiteTime={whiteTime}
          blackTime={blackTime}
          formatTime={formatTime}
          isMultiplayerGame={isMultiplayerGame}
          isMultiplayerStarted={isMultiplayerStarted}
          multiplayerNotice={multiplayerNotice}
          multiplayerSide={multiplayerSide}
          evalValue={evalValue}
          mateValue={mateValue}
          stockfish={stockfish}
          displayTurn={currentTurn}
          displayBoard={displayBoard}
          displaySelectedSquare={displaySelectedSquare}
          displayValidMoves={displayValidMoves}
          displayKingInCheckPos={displayKingInCheckPos}
          displayLastMove={displayLastMove}
          handleSquareClick={handleSquareClick}
          displayRankLabels={displayRankLabels}
          displayFileLabels={displayFileLabels}
          gameState={gameState}
          isReviewMode={isReviewMode}
          activePieceImages={activePieceImages || {}}
          boardThemeColors={boardThemeColors}
          uiSettings={uiSettings}
          showPromotionUI={showPromotionUI}
          promotionSquare={promotionSquare}
          onPromotion={handlePromotion}
          onCancel={handleCancelPromotion}
        />
      </div>

      {/*
        BUG-02/04/11/18 FIX:
        GameModals owns ALL modal rendering — promotion UI, game-over modal,
        draw offer, settings modal, and game settings modal.
        Props are now correctly named to match what GameModals.jsx expects.
        The duplicate {showAppSettings && <SettingsModal>} and
        {showGameSettings && <GameSettingsModal>} blocks have been removed
        from App's JSX — they are rendered inside GameModals instead.
      */}
      <GameModals
        isGameOverUIState={isGameOverUIState}
        gameState={gameState}
        currentTurn={currentTurn}
        handleNewGame={handleNewGame}
        handleRematch={handleRematch}
        handleGameReview={handleOpenGameAnalysis}
        setShowGameOverUI={setShowGameOverUI}

        showDrawOffer={showDrawOffer}
        incomingDrawOfferSide={incomingDrawOfferSide}
        handleAcceptDraw={handleAcceptDraw}
        handleDeclineDraw={handleDeclineDraw}

        showAppSettings={showAppSettings}
        setShowAppSettings={setShowAppSettings}
        boardSurfaceOptions={boardSurfaceOptions}
        pieceSetOptions={pieceSetOptions}

        showGameSettings={showGameSettings}
        setShowGameSettings={setShowGameSettings}
        playerNames={playerNames}
        updatePlayerName={updatePlayerName}
        resetPlayerNames={resetPlayerNames}

        isMultiplayerGame={isMultiplayerGame}
        multiplayerSide={multiplayerSide}
        setIsBoardFlipped={setIsBoardFlipped}
        handleResign={handleResign}
        handleOfferDraw={handleOfferDraw}
        uiCapabilities={uiCapabilities}
      />

      {/*
        BUG-03/17 FIX:
        MobileGameArea now receives correct prop names:
        - showMobileStartPanel (boolean, not uiState + gameStarted)
        - onResign, onOfferDraw, onSelectTimeControl, onStartGame,
          onSelectGameMode, onComputerDifficultyChange (not handle* variants)
        - All missing review and game panel props are now passed.
      */}
      <MobileGameArea
        showMobileStartPanel={showMobileStartPanel}
        selectedTimeControl={selectedTimeControl}
        onSelectTimeControl={handleSelectTimeControl}
        gameMode={gameMode}
        onSelectGameMode={handleSelectGameMode}
        computerDifficulty={computerDifficulty}
        onComputerDifficultyChange={handleComputerDifficultyChange}
        onStartGame={handleStartConfiguredGame}
        canStartGame={uiCapabilities.canStartGame}
        gameStarted={gameStarted}
        moveHistory={activeMoveHistory}
        currentTurn={currentTurn}
        onResign={handleResign}
        onOfferDraw={handleOfferDraw}
        gameState={gameState}
        highlightResign={highlightResign}
        isReviewMode={isReviewMode}
        reviewIndex={reviewIndex}
        reviewHistoryLength={reviewHistoryLength}
        isPlaying={isPlaying}
        onReviewPrevious={handleReviewPrevious}
        onReviewNext={handleReviewNext}
        onReviewStart={handleReviewStart}
        onReviewEnd={handleReviewEnd}
        onReviewTogglePlay={handleReviewTogglePlay}
        onExitReview={handleExitReview}
        onGameAnalysis={handleOpenGameAnalysis}
        canUseInGameActions={uiCapabilities.canUseInGameActions}
      />

      <MobileNavigation
        handlePlaySelectFromNav={handlePlaySelectFromNav}
        gameMode={gameMode}
        handleRefreshBoardView={handleRefreshBoardView}
        setShowAppSettings={setShowAppSettings}
        setIsBoardFlipped={setIsBoardFlipped}
        effectiveBoardFlipped={effectiveBoardFlipped}
      />

      <RightPanel
        selectedTimeControl={selectedTimeControl}
        gameStarted={gameStarted}
        moveHistory={activeMoveHistory}
        currentTurn={currentTurn}
        gameState={gameState}
        isMultiplayerGame={isMultiplayerGame}
        gameMode={gameMode}
        computerDifficulty={computerDifficulty}
        playerColor={playerColor}
        highlightResign={highlightResign}
        isEngineReady={stockfish?.isEngineReady ?? true}
        canUseInGameActions={uiCapabilities.canUseInGameActions}
        canStartGame={uiCapabilities.canStartGame}
        canPlayFriend={uiCapabilities.canOpenMultiplayer}
        isReviewMode={isReviewMode}
        reviewIndex={reviewIndex}
        reviewHistoryLength={activeMoveHistory.length}
        isPlaying={isPlaying}
        onSelectTimeControl={handleSelectTimeControl}
        onStartGame={handleStartConfiguredGame}
        onNewGame={handleNewGameRequest}
        onResign={handleResign}
        onOfferDraw={handleOfferDraw}
        onPlayFriend={handlePlayFriend}
        onSelectGameMode={handleSelectGameMode}
        onComputerDifficultyChange={handleComputerDifficultyChange}
        onPlayerColorChange={handlePlayerColorChange}
        onReviewPrevious={handleReviewPrevious}
        onReviewNext={handleReviewNext}
        onReviewStart={handleReviewStart}
        onReviewEnd={handleReviewEnd}
        onReviewTogglePlay={handleReviewTogglePlay}
        onExitReview={handleExitReview}
        onGameAnalysis={handleOpenGameAnalysis}
      />
    </div>
  );
}

export default App;

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { atom, useAtomValue } from 'jotai';
import tinycolor from 'tinycolor2';
import ChessBoardView from '@/components/ChessBoardView';
import EvaluationBar from './evaluationBar';
import PlayerHeader from './playerHeader';
import { Color, MoveClassification } from '@analysis/types/enums';
import { pieceSetAtom } from './states';
import { useChessActions } from '@analysis/hooks/useChessActions';

import { buildPieceImages } from '@/constants/theme';
import { boardThemeAtom } from '@/state/themeState';
import { BOARD_THEME_MAP } from '@/constants/boardThemes';

function toDisplayCoords(row, col, isWhiteBottom) {
  if (isWhiteBottom) return { row, col };
  return { row: 7 - row, col: 7 - col };
}

function toEngineCoords(row, col, isWhiteBottom) {
  if (isWhiteBottom) return { row, col };
  return { row: 7 - row, col: 7 - col };
}

function coordsToAlgebraic(row, col) {
  const file = String.fromCharCode(97 + col);
  const rank = String(8 - row);
  return `${file}${rank}`;
}

function algebraicToCoords(square) {
  if (!square) return null;
  const file = square.charCodeAt(0) - 97;
  const rank = Number(square[1]);
  return { row: 8 - rank, col: file };
}

function toPieceCode(piece) {
  if (!piece) return null;
  const pieceType = piece.type === 'p' ? 'p' : piece.type.toUpperCase();
  return `${piece.color}${pieceType}`;
}

function flipBoard(board) {
  return board
    .slice()
    .reverse()
    .map((row) => row.slice().reverse());
}

export default function Board({
  id: boardId,
  canPlay,
  gameAtom,
  boardSize,
  whitePlayer,
  blackPlayer,
  boardOrientation = Color.White,
  currentPositionAtom,
  showBestMoveArrow = false,
  showPlayerMoveIconAtom,
  showEvaluationBar = false
}) {
  const game = useAtomValue(gameAtom);
  const currentPosition = useAtomValue(currentPositionAtom);
  const boardThemeKey = useAtomValue(boardThemeAtom);
  const pieceSet = useAtomValue(pieceSetAtom);
  const isWhiteBottom = boardOrientation === Color.White;
  const { playMove } = useChessActions(gameAtom);

  const [selectedSquare, setSelectedSquare] = useState(null);
  const [validMoves, setValidMoves] = useState([]);
  const [boardHeight, setBoardHeight] = useState(boardSize || 400);
  const [boardWidth, setBoardWidth] = useState(boardSize || 400);
  const [showPromotionUI, setShowPromotionUI] = useState(false);
  const [promotionSquare, setPromotionSquare] = useState(null);
  const [pendingPromotionMove, setPendingPromotionMove] = useState(null);
  const boardContainerRef = useRef(null);

  useEffect(() => {
    const node = boardContainerRef.current;
    if (!node) return;
    const updateSize = () => {
      if (node.offsetHeight > 0 && node.offsetWidth > 0) {
        setBoardHeight((prev) => Math.abs(prev - node.offsetHeight) > 10 ? node.offsetHeight : prev);
        setBoardWidth((prev) => Math.abs(prev - node.offsetWidth) > 10 ? node.offsetWidth : prev);
      }
    };
    updateSize();
    const observer = new ResizeObserver(updateSize);
    observer.observe(node);
    return () => observer.disconnect();
  }, [boardSize]);

  const boardHistoryLength = game.history().length;

  useEffect(() => {
    setSelectedSquare(null);
    setValidMoves([]);
  }, [game, boardHistoryLength]);

  const engineBoard = useMemo(() => {
    const rawBoard = game.board();
    return rawBoard.map((row) => row.map((piece) => toPieceCode(piece)));
  }, [game, boardHistoryLength]);

  const boardForRender = useMemo(() => {
    return isWhiteBottom ? engineBoard : flipBoard(engineBoard);
  }, [engineBoard, isWhiteBottom]);

  const sideToMove = game.turn();
  const isGameOver = game.isGameOver();

  const isPiecePlayable = useCallback(
    ({ piece }) => {
      if (isGameOver || !canPlay) return false;
      if (canPlay === true || canPlay === piece[0]) return true;
      return false;
    },
    [canPlay, isGameOver]
  );

  const onSquareClick = useCallback(
    (displayRow, displayCol) => {
      if (isGameOver) return;

      const { row, col } = toEngineCoords(displayRow, displayCol, isWhiteBottom);
      const clickedSquare = coordsToAlgebraic(row, col);
      const piece = engineBoard[row]?.[col] || null;
      const isOwnPiece = !!piece && piece[0] === sideToMove && isPiecePlayable({ piece });

      if (selectedSquare) {
        const fromSquare = coordsToAlgebraic(selectedSquare.row, selectedSquare.col);
        const candidateMoves = game.moves({ square: fromSquare, verbose: true });
        const move = candidateMoves.find((m) => m.to === clickedSquare);

        if (move) {
          const isPromotion = move.flags.includes('p');
          if (isPromotion) {
            setPendingPromotionMove({ from: move.from, to: move.to });
            setPromotionSquare({
              row: displayRow,
              col: displayCol,
              color: sideToMove,
            });
            setShowPromotionUI(true);
            return;
          }

          playMove({
            from: move.from,
            to: move.to,
          });
          setSelectedSquare(null);
          setValidMoves([]);
          return;
        }
      }

      if (isOwnPiece) {
        setSelectedSquare({ row, col });
        const candidateMoves = game.moves({ square: clickedSquare, verbose: true });
        setValidMoves(
          candidateMoves.map((m) => {
            const sq = algebraicToCoords(m.to);
            const dispSq = toDisplayCoords(sq.row, sq.col, isWhiteBottom);
            return { to: dispSq };
          })
        );
      } else {
        setSelectedSquare(null);
        setValidMoves([]);
      }
    },
    [game, isGameOver, isWhiteBottom, engineBoard, sideToMove, selectedSquare, playMove, isPiecePlayable]
  );

  const selectedForRender = useMemo(() => {
    if (!selectedSquare) return null;
    return toDisplayCoords(selectedSquare.row, selectedSquare.col, isWhiteBottom);
  }, [selectedSquare, isWhiteBottom]);

  const lastMove = useMemo(() => {
    if (!currentPosition) return null;

    let moveObj = currentPosition.move;
    if (!moveObj && game.history().length > 0) {
      const h = game.history({ verbose: true });
      moveObj = h[h.length - 1];
    }
    if (!moveObj || !moveObj.from || !moveObj.to) return null;

    const fromSq = algebraicToCoords(moveObj.from);
    const toSq = algebraicToCoords(moveObj.to);
    return {
      from: toDisplayCoords(fromSq.row, fromSq.col, isWhiteBottom),
      to: toDisplayCoords(toSq.row, toSq.col, isWhiteBottom),
    };
  }, [currentPosition, game, isWhiteBottom]);

  const kingInCheckPos = useMemo(() => {
    if (!game.inCheck()) return null;
    let kPos = null;
    for (let r = 0; r < 8; r++) {
      for (let c = 0; c < 8; c++) {
        const piece = engineBoard[r][c];
        if (piece === `${sideToMove}K`) {
          kPos = { row: r, col: c };
          break;
        }
      }
    }
    if (!kPos) return null;
    return toDisplayCoords(kPos.row, kPos.col, isWhiteBottom);
  }, [game, engineBoard, sideToMove, isWhiteBottom]);

  const moveClassification = currentPosition?.eval?.moveClassification || null;

  const handlePromotion = useCallback(
    (promoType) => {
      if (!pendingPromotionMove) return;
      playMove({
        from: pendingPromotionMove.from,
        to: pendingPromotionMove.to,
        promotion: promoType,
      });
      setPendingPromotionMove(null);
      setShowPromotionUI(false);
      setSelectedSquare(null);
      setValidMoves([]);
    },
    [pendingPromotionMove, playMove]
  );

  const handleCancelPromotion = useCallback(() => {
    setPendingPromotionMove(null);
    setShowPromotionUI(false);
    setSelectedSquare(null);
    setValidMoves([]);
  }, []);

  const activePieceImages = useMemo(() => buildPieceImages(pieceSet), [pieceSet]);

  const boardTheme = useMemo(() => {
    return BOARD_THEME_MAP[boardThemeKey] || BOARD_THEME_MAP['classic-blue'];
  }, [boardThemeKey]);

  const arrowCoordinates = useMemo(() => {
    if (!showBestMoveArrow) return null;
    const bestMove = currentPosition?.lastEval?.bestMove;
    if (typeof bestMove !== 'string' || bestMove.length < 4) return null;

    if (moveClassification === MoveClassification.Best || 
        moveClassification === MoveClassification.Book || 
        moveClassification === MoveClassification.Brilliant || 
        moveClassification === MoveClassification.Great) {
      return null;
    }

    const from = algebraicToCoords(bestMove.slice(0, 2));
    const to = algebraicToCoords(bestMove.slice(2, 4));
    if (!from || !to) return null;
    const fromDisplay = toDisplayCoords(from.row, from.col, isWhiteBottom);
    const toDisplay = toDisplayCoords(to.row, to.col, isWhiteBottom);
    return { from: fromDisplay, to: toDisplay };
  }, [currentPosition, showBestMoveArrow, moveClassification, isWhiteBottom]);

  const fallbackAtom = useMemo(() => atom(false), []);
  const showPlayerMoveIcon = useAtomValue(showPlayerMoveIconAtom || fallbackAtom);

  return (
    <div className="flex w-full items-center justify-center">
      {showEvaluationBar && (
        <EvaluationBar
          height={boardHeight}
          boardOrientation={isWhiteBottom ? Color.White : Color.Black}
          currentPositionAtom={currentPositionAtom}
        />
      )}
      <div className="flex flex-col items-center flex-1 px-1">
        <PlayerHeader
          color={isWhiteBottom ? Color.Black : Color.White}
          gameAtom={gameAtom}
          player={isWhiteBottom ? blackPlayer : whitePlayer}
        />
        <div ref={boardContainerRef} className="relative w-full max-w-[800px] aspect-square my-1">
          <ChessBoardView
            board={boardForRender}
            selectedSquare={selectedForRender}
            validMoves={validMoves}
            kingInCheckPos={kingInCheckPos}
            lastMove={lastMove}
            moveClassification={moveClassification}
            showAnalysisMoveIcon={showPlayerMoveIcon}
            onSquareClick={onSquareClick}
            rankLabels={[]}
            fileLabels={[]}
            gameState={isGameOver ? 'game-over' : 'playing'}
            isReviewMode={false}
            enableDrag={true}
            pieceAnimation={true}
            dragAnimation={true}
            activePieceImages={activePieceImages}
            boardTheme={boardTheme}
            showPromotionUI={showPromotionUI}
            promotionSquare={promotionSquare}
            onPromotion={handlePromotion}
            onCancel={handleCancelPromotion}
          />

          {arrowCoordinates && (
            <svg
              className="pointer-events-none absolute inset-0 z-20"
              width="100%"
              height="100%"
              viewBox={`0 0 ${boardWidth} ${boardHeight}`}
            >
              <defs>
                <marker id="analysis-best-move-arrow" markerWidth="8" markerHeight="8" refX="6" refY="4" orient="auto">
                  <path d="M0,0 L8,4 L0,8 z" fill="rgba(34, 197, 94, 0.95)" />
                </marker>
              </defs>
              <line
                x1={(arrowCoordinates.from.col + 0.5) * (boardWidth / 8)}
                y1={(arrowCoordinates.from.row + 0.5) * (boardHeight / 8)}
                x2={(arrowCoordinates.to.col + 0.5) * (boardWidth / 8)}
                y2={(arrowCoordinates.to.row + 0.5) * (boardHeight / 8)}
                stroke="rgba(34, 197, 94, 0.75)"
                strokeWidth={Math.max(4, boardWidth * 0.02)}
                markerEnd="url(#analysis-best-move-arrow)"
                opacity={0.8}
              />
            </svg>
          )}
        </div>
        <PlayerHeader
          color={isWhiteBottom ? Color.White : Color.Black}
          gameAtom={gameAtom}
          player={isWhiteBottom ? whitePlayer : blackPlayer}
        />
      </div>
    </div>
  );
}

import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
import { useAtomValue } from 'jotai';
import tinycolor from 'tinycolor2';
import ChessBoardView from '../../../../../components/ChessBoardView.jsx';
import EvaluationBar from '@analysis/components/board/evaluationBar';
import { Color, MoveClassification } from '@analysis/types/enums';
import { boardAtom, boardOrientationAtom, currentPositionAtom, gameAtom, gameEvalAtom, showBestMoveArrowAtom, showPlayerMoveIconAtom } from '../states';
import { boardThemeAtom } from '@/state/themeState';
import { BOARD_THEME_MAP } from '@/constants/boardThemes';
import { pieceSetAtom } from '@analysis/components/board/states';
import { toPublicPath } from '@/utils/assetPath';
import { useChessActions } from '@analysis/hooks/useChessActions';
import { buildPieceImages } from '@/constants/theme';

function bestMoveArrowCoords(bestMove, isWhiteBottom) {
  if (typeof bestMove !== 'string' || bestMove.length < 4) return null;
  const from = algebraicToCoords(bestMove.slice(0, 2));
  const to = algebraicToCoords(bestMove.slice(2, 4));
  const fromDisplay = toDisplayCoords(from.row, from.col, isWhiteBottom);
  const toDisplay = toDisplayCoords(to.row, to.col, isWhiteBottom);
  return { from: fromDisplay, to: toDisplay };
}

function toDisplayCoords(row, col, isWhiteBottom) {
  if (isWhiteBottom) return { row, col };
  return { row: 7 - row, col: 7 - col };
}

function toEngineCoords(row, col, isWhiteBottom) {
  if (isWhiteBottom) return { row, col };
  return { row: 7 - row, col: 7 - col };
}

function coordsToAlgebraic(row, col) {
  const file = String.fromCharCode(97 + col);
  const rank = String(8 - row);
  return `${file}${rank}`;
}

function algebraicToCoords(square) {
  const file = square.charCodeAt(0) - 97;
  const rank = Number(square[1]);
  return { row: 8 - rank, col: file };
}

function toPieceCode(piece) {
  if (!piece) return null;
  const pieceType = piece.type === 'p' ? 'p' : piece.type.toUpperCase();
  return `${piece.color}${pieceType}`;
}

function flipBoard(board) {
  return board
    .slice()
    .reverse()
    .map((row) => row.slice().reverse());
}

function BitboardAnalysisBoard() {
  const analysisBoard = useAtomValue(boardAtom);
  const game = useAtomValue(gameAtom);
  const isWhiteBottom = useAtomValue(boardOrientationAtom);
  const currentPosition = useAtomValue(currentPositionAtom);
  const gameEval = useAtomValue(gameEvalAtom);
  const boardThemeKey = useAtomValue(boardThemeAtom);
  const pieceSet = useAtomValue(pieceSetAtom);
  const showBestMoveArrow = useAtomValue(showBestMoveArrowAtom);
  const showPlayerMoveIcon = useAtomValue(showPlayerMoveIconAtom);
  const { playMove: playBoardMove } = useChessActions(boardAtom);

  const [selectedSquare, setSelectedSquare] = useState(null);
  const [validMoves, setValidMoves] = useState([]);
  const [boardHeight, setBoardHeight] = useState(560);
  const [boardWidth, setBoardWidth] = useState(560);
  const [showPromotionUI, setShowPromotionUI] = useState(false);
  const [promotionSquare, setPromotionSquare] = useState(null);
  const [pendingPromotionMove, setPendingPromotionMove] = useState(null);
  const boardContainerRef = useRef(null);

  useEffect(() => {
    const node = boardContainerRef.current;
    if (!node) return;
    const updateSize = () => {
      if (node.offsetHeight > 0 && node.offsetWidth > 0) {
        setBoardHeight((prev) => Math.abs(prev - node.offsetHeight) > 10 ? node.offsetHeight : prev);
        setBoardWidth((prev) => Math.abs(prev - node.offsetWidth) > 10 ? node.offsetWidth : prev);
      }
    };
    updateSize();
    const observer = new ResizeObserver(updateSize);
    observer.observe(node);
    return () => observer.disconnect();
  }, []);

  const boardHistoryLength = analysisBoard.history().length;

  useEffect(() => {
    setSelectedSquare(null);
    setValidMoves([]);
  }, [analysisBoard, boardHistoryLength]);

  const engineBoard = useMemo(() => {
    const rawBoard = analysisBoard.board();
    return rawBoard.map((row) => row.map((piece) => toPieceCode(piece)));
  }, [analysisBoard, boardHistoryLength]);

  const sideToMove = analysisBoard.turn();
  const isGameOver = analysisBoard.isCheckmate() || analysisBoard.isStalemate();

  const onSquareClick = useCallback(
    (displayRow, displayCol) => {
      if (isGameOver) return;

      const { row, col } = toEngineCoords(displayRow, displayCol, isWhiteBottom);
      const clickedSquare = coordsToAlgebraic(row, col);
      const piece = engineBoard[row]?.[col] || null;
      const isOwnPiece = !!piece && piece[0] === sideToMove;

      if (selectedSquare) {
        const fromSquare = coordsToAlgebraic(selectedSquare.row, selectedSquare.col);
        const candidateMoves = analysisBoard.moves({ square: fromSquare, verbose: true });
        const move = candidateMoves.find((m) => m.to === clickedSquare);

        if (move) {
          const isPromotion = move.flags.includes('p');
          if (isPromotion) {
            setPendingPromotionMove({ from: move.from, to: move.to });
            setPromotionSquare({
              row: displayRow,
              col: displayCol,
              color: sideToMove,
            });
            setShowPromotionUI(true);
            return;
          }

          playBoardMove({
            from: move.from,
            to: move.to,
          });
          setSelectedSquare(null);
          setValidMoves([]);
          return;
        }
      }

      if (!isOwnPiece) {
        setSelectedSquare(null);
        setValidMoves([]);
        return;
      }

      const fromMoves = analysisBoard.moves({ square: clickedSquare, verbose: true });
      setSelectedSquare({ row, col });
      setValidMoves(
        fromMoves.map((m) => {
          const targetCoords = algebraicToCoords(m.to);
          const target = toDisplayCoords(targetCoords.row, targetCoords.col, isWhiteBottom);
          return { row: target.row, col: target.col };
        })
      );
    },
    [
      analysisBoard,
      engineBoard,
      isGameOver,
      isWhiteBottom,
      playBoardMove,
      selectedSquare,
      sideToMove,
    ]
  );

  const handlePromotion = useCallback(
    (pieceType) => {
      if (pendingPromotionMove) {
        playBoardMove({
          from: pendingPromotionMove.from,
          to: pendingPromotionMove.to,
          promotion: pieceType.toLowerCase(),
        });
      }
      setShowPromotionUI(false);
      setPromotionSquare(null);
      setPendingPromotionMove(null);
      setSelectedSquare(null);
      setValidMoves([]);
    },
    [pendingPromotionMove, playBoardMove]
  );

  const handleCancelPromotion = useCallback(() => {
    setShowPromotionUI(false);
    setPromotionSquare(null);
    setPendingPromotionMove(null);
    setSelectedSquare(null);
    setValidMoves([]);
  }, []);

  const boardForRender = useMemo(
    () => (isWhiteBottom ? engineBoard : flipBoard(engineBoard)),
    [engineBoard, isWhiteBottom]
  );

  const selectedForRender = useMemo(() => {
    if (!selectedSquare) return null;
    return toDisplayCoords(selectedSquare.row, selectedSquare.col, isWhiteBottom);
  }, [selectedSquare, isWhiteBottom]);

  const kingInCheckPos = useMemo(() => {
    if (!analysisBoard.inCheck()) return null;
    for (let row = 0; row < 8; row++) {
      for (let col = 0; col < 8; col++) {
        const piece = engineBoard[row]?.[col];
        if (piece === `${sideToMove}K`) {
          return toDisplayCoords(row, col, isWhiteBottom);
        }
      }
    }
    return null;
  }, [analysisBoard, engineBoard, isWhiteBottom, sideToMove]);

  const lastMove = useMemo(() => {
    const history = analysisBoard.history({ verbose: true });
    const lastMoveInfo = history.at(-1);
    if (!lastMoveInfo) return null;
    const fromCoords = algebraicToCoords(lastMoveInfo.from);
    const toCoords = algebraicToCoords(lastMoveInfo.to);
    return {
      from: toDisplayCoords(fromCoords.row, fromCoords.col, isWhiteBottom),
      to: toDisplayCoords(toCoords.row, toCoords.col, isWhiteBottom),
      piece: lastMoveInfo.piece,
    };
  }, [analysisBoard, boardHistoryLength, isWhiteBottom]);

  const moveClassification = useMemo(() => {
    const instantClassification = gameEval?.positions?.[boardHistoryLength]?.moveClassification;
    if (instantClassification) return instantClassification;
    return currentPosition?.eval?.moveClassification;
  }, [boardHistoryLength, currentPosition?.eval?.moveClassification, gameEval]);

  const activePieceImages = useMemo(() => buildPieceImages(pieceSet), [pieceSet]);

  const boardTheme = useMemo(() => {
    return BOARD_THEME_MAP[boardThemeKey] || BOARD_THEME_MAP['classic-blue'];
  }, [boardThemeKey]);

  const arrowCoordinates = useMemo(() => {
    if (!showBestMoveArrow) return null;
    if ([
      MoveClassification.Best,
      MoveClassification.Book,
      MoveClassification.Brilliant,
      MoveClassification.Great,
    ].includes(moveClassification)) {
      return null;
    }
    const bestMove = currentPosition?.lastEval?.lines?.[0]?.pv?.[0];
    return bestMoveArrowCoords(bestMove, isWhiteBottom);
  }, [showBestMoveArrow, moveClassification, currentPosition?.lastEval?.lines, isWhiteBottom]);

  const players = useMemo(() => {
    const headers = game.getHeaders();
    const whiteName = headers.White && headers.White !== '?' ? headers.White : 'White';
    const blackName = headers.Black && headers.Black !== '?' ? headers.Black : 'Black';
    const isLoaded = boardHistoryLength > 0 || (headers.White && headers.White !== '?') || (headers.Black && headers.Black !== '?');
    return {
      white: whiteName,
      black: blackName,
      isLoaded,
    };
  }, [boardHistoryLength, game]);

  const topPlayerName = isWhiteBottom ? players.black : players.white;
  const bottomPlayerName = isWhiteBottom ? players.white : players.black;
  const topDisplayName = players.isLoaded ? topPlayerName : (isWhiteBottom ? 'Black' : 'White');
  const bottomDisplayName = players.isLoaded ? bottomPlayerName : (isWhiteBottom ? 'White' : 'Black');

  const renderPlayerRow = (name, color) => {
    const initial = (name?.trim()?.[0] || '?').toUpperCase();
    return (
      <div className="flex items-center gap-2 text-cyan-50">
        <div className="w-7 h-7 rounded-full border border-cyan-200/60 bg-cyan-800/60 flex items-center justify-center text-xs font-semibold">
          {initial}
        </div>
        <div className="text-sm font-medium tracking-wide">{name}</div>
        <div className="text-xs text-cyan-200/80 uppercase">{color}</div>
      </div>
    );
  };

  return (
    <div className="mt-3">
      <div className="mb-2">
        {renderPlayerRow(topDisplayName, isWhiteBottom ? 'Black' : 'White')}
      </div>
      <div className="flex items-stretch justify-center w-full gap-2">
        <EvaluationBar
          height={boardHeight}
          boardOrientation={isWhiteBottom ? Color.White : Color.Black}
          currentPositionAtom={currentPositionAtom}
        />
        <div ref={boardContainerRef} className="relative h-[calc(100vh-200px)] max-h-[800px] aspect-square">
          <ChessBoardView
            board={boardForRender}
            selectedSquare={selectedForRender}
            validMoves={validMoves}
            kingInCheckPos={kingInCheckPos}
            lastMove={lastMove}
            moveClassification={moveClassification}
            showAnalysisMoveIcon={showPlayerMoveIcon}
            onSquareClick={onSquareClick}
            rankLabels={[]}
            fileLabels={[]}
            gameState={isGameOver ? 'game-over' : 'playing'}
            isReviewMode={false}
            enableDrag={true}
            pieceAnimation={true}
            dragAnimation={true}
            activePieceImages={activePieceImages}
            boardTheme={boardTheme}
            showPromotionUI={showPromotionUI}
            promotionSquare={promotionSquare}
            onPromotion={handlePromotion}
            onCancel={handleCancelPromotion}
          />

          {arrowCoordinates && (
            <svg
              className="pointer-events-none absolute inset-0 z-20"
              width={boardWidth}
              height={boardHeight}
              viewBox={`0 0 ${boardWidth} ${boardHeight}`}
            >
              <defs>
                <marker id="analysis-best-move-arrow" markerWidth="8" markerHeight="8" refX="6" refY="4" orient="auto">
                  <path d="M0,0 L8,4 L0,8 z" fill="rgba(34, 197, 94, 0.95)" />
                </marker>
              </defs>
              <line
                x1={(arrowCoordinates.from.col + 0.5) * (boardWidth / 8)}
                y1={(arrowCoordinates.from.row + 0.5) * (boardHeight / 8)}
                x2={(arrowCoordinates.to.col + 0.5) * (boardWidth / 8)}
                y2={(arrowCoordinates.to.row + 0.5) * (boardHeight / 8)}
                stroke="rgba(34, 197, 94, 0.92)"
                strokeWidth={Math.max(4, boardWidth / 85)}
                strokeLinecap="round"
                markerEnd="url(#analysis-best-move-arrow)"
              />
            </svg>
          )}
        </div>
      </div>
      <div className="mt-2">
        {renderPlayerRow(bottomDisplayName, isWhiteBottom ? 'White' : 'Black')}
      </div>
    </div>
  );
}

export default BitboardAnalysisBoard;

